import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String userInput = scanner.nextLine(); // Read the entire line

        // Limit the size of the buffer to the length of userInput or a maximum size
        int bufferSize = Math.min(userInput.length(), 10);
        char[] buffer = new char[bufferSize];

        userInput.getChars(0, bufferSize, buffer, 0); // Copy only up to bufferSize characters

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
